functions.color-function:
main: (i) => {
	function color(i) {
		let c = 0
		if (i==2) return colorHelper(200,20,20)
		if (i) c = 250

		return colorHelper(c, c, c)
	}
	function colorHelper(r, g, b) {
		return b + g * 0x100 + r* 0x10000
	}
	return color(i)
}

