const outline = (a,b,r,f) => {

	if(!f(a, b)) return 1
	const dx = [-1, 0, 1, -1, 1, -1, 0, 1]
	const dy = [-1, -1, -1, 0, 0, 1, 1, 1]
	for(let i=0; i<8; i++) {
		const newa = a+dx[i]/r
		const newb = b+dy[i]/r
		if(!f(newa, newb))
			return 0
	}
	return 1
}


	function calc(x, y) { 
	let x2 = (x-40)/20
	let y2 = (y-40)/20
	let v = outline(x2, y2, 20, sqr)
	if ((x == 40 || y ==  40 || (!(x2 * 20 % 20) && y == 41) || (!(x2 * 20 % 100) && y == 42) || (!(y2 * 20 % 20) && x == 41) || (!((y2) * 20 % 100) && x == 42)) && v) return 2;
	return v

	} 
 return calc(x, y) 
}
